-- SEED: повний асортимент Spice Market з Excel
DO $$ DECLARE cat_mono uuid; cat_blend uuid; cat_auth uuid; cat_tea uuid; BEGIN
  SELECT id INTO cat_mono  FROM public.categories WHERE slug='mono';
  SELECT id INTO cat_blend FROM public.categories WHERE slug='blend';
  SELECT id INTO cat_auth  FROM public.categories WHERE slug='gift';
  SELECT id INTO cat_tea   FROM public.categories WHERE slug='tea';
  -- ── МОНО СПЕЦІЇ ──
  -- ── КЛАСИЧНІ СУМІШІ ──
  -- ── АВТОРСЬКІ СУМІШІ ──
  -- ── ЧАЇ ──
END $$;